<?php declare(strict_types=1);
namespace App\Repositories;
final class ChannelRepository extends AbstractRepository { public function all():array{return $this->pdo()->query('SELECT id,name,description,rtmp_url,status,enabled,is_default,created_at FROM channels ORDER BY is_default DESC,created_at DESC')->fetchAll();} public function find(int $id):?array{$s=$this->pdo()->prepare('SELECT * FROM channels WHERE id=?');$s->execute([$id]);return $s->fetch()?:null;} public function create(array $d):void{$this->pdo()->prepare('INSERT INTO channels(name,description,rtmp_url,stream_key,enabled,is_default)VALUES(?,?,?,?,?,?)')->execute([$d['name'],$d['description'],$d['rtmp_url'],$d['stream_key'],$d['enabled'],$d['is_default']]);} public function update(int $id,array $d):void{$this->pdo()->prepare('UPDATE channels SET name=?,description=?,rtmp_url=?,stream_key=?,enabled=?,is_default=? WHERE id=?')->execute([$d['name'],$d['description'],$d['rtmp_url'],$d['stream_key'],$d['enabled'],$d['is_default'],$id]);} public function delete(int $id):void{$this->pdo()->prepare('DELETE FROM channels WHERE id=?')->execute([$id]);} public function setStatus(int $id,string $status):void{$this->pdo()->prepare('UPDATE channels SET status=? WHERE id=?')->execute([$status,$id]);} public function clearDefaults():void{$this->pdo()->query('UPDATE channels SET is_default=0');} }
